// App.js
import React, { useState, useEffect } from "react";
import axios from "axios";
import MarketTable from "./MarketTable";
import AnalyticsTable from "./AnalyticsTable";
import RankingTable from "./RankingTable";
import StrategyRun from "./StrategyRun";
import BTCChart from "./BTCChart";

function App() {
  const [market, setMarket] = useState([]);
  const [analytics, setAnalytics] = useState({});
  const [ranking, setRanking] = useState([]);

  const fetchMarket = async () => {
    const res = await axios.get("http://127.0.0.1:8000/market");
    setMarket(res.data.slice(0, 50));
  };

  const fetchAnalytics = async () => {
    const res = await axios.get("http://127.0.0.1:8000/analytics");
    setAnalytics(res.data);
  };

  const fetchRanking = async () => {
    const res = await axios.get("http://127.0.0.1:8000/ranking");
    setRanking(res.data);
  };

  useEffect(() => {
    fetchMarket();
    fetchAnalytics();
    fetchRanking();
    const interval = setInterval(() => {
      fetchMarket();
      fetchAnalytics();
      fetchRanking();
    }, 30000); // refresh every 30s
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ padding: 20 }}>
      <h1>Crypto Dashboard</h1>
      <BTCChart market={market} />
      <MarketTable market={market} />
      <AnalyticsTable analytics={analytics} />
      <RankingTable ranking={ranking} />
      <StrategyRun />
    </div>
  );
}

export default App;
